const Router={routes:{},register(t,e){this.routes[t]=e},async navigate(t){t=t||"/";const e=document.getElementById("main-content");e.innerHTML='<div class="loader-container"><div class="loader"></div><p>Cargando...</p></div>',document.querySelectorAll(".nav-link").forEach(e=>{e.classList.toggle("active",e.dataset.route===t)});const a=this.routes[t];if(a)try{await a(e)}catch(t){e.innerHTML=`<div class="alert alert-error">Error: ${t.message}</div>`}},init(){window.addEventListener("hashchange",()=>{const t=window.location.hash.slice(1)||"/";this.navigate(t)});const t=window.location.hash.slice(1)||"/";this.navigate(t)}};